body.content:
StaticConfiguration(kind: Network_entry.kind, provider: Provider()) { entry in
            VStack(spacing: 10) {
                if Provider().systemWidgetsUpdatesState || entry.isPreview, let value = entry.value {
                    VStack {
                        HStack {
                            VStack {
                                VStack(spacing: 0) {
                                    Text(Units(bytes: value.bandwidth.download).getReadableTuple(base: self.base, unit: self.speedUnit).0).font(.system(size: 24, weight: .regular))
                                    Text(Units(bytes: value.bandwidth.download).getReadableTuple(base: self.base, unit: self.speedUnit).1).font(.system(size: 10, weight: .regular))
                                }
                                Text("Download").font(.system(size: 12, weight: .regular)).foregroundColor(.gray)
                            }.frame(maxWidth: .infinity)
                            VStack {
                                VStack(spacing: 0) {
                                    Text(Units(bytes: value.bandwidth.upload).getReadableTuple(base: self.base, unit: self.speedUnit).0).font(.system(size: 24, weight: .regular))
                                    Text(Units(bytes: value.bandwidth.upload).getReadableTuple(base: self.base, unit: self.speedUnit).1).font(.system(size: 10, weight: .regular))
                                }
                                Text("Upload").font(.system(size: 12, weight: .regular)).foregroundColor(.gray)
                            }.frame(maxWidth: .infinity)
                        }
                        .frame(maxHeight: .infinity)
                        VStack(spacing: 3) {
                            HStack {
                                Text("Status").font(.system(size: 12, weight: .regular)).foregroundColor(.secondary)
                                Spacer()
                                Text(value.status ? "UP" : "DOWN")
                                    .font(.system(size: 11, weight: .semibold))
                            }
                            if let interface = value.interface {
                                HStack {
                                    Text("Interface").font(.system(size: 12, weight: .regular)).foregroundColor(.secondary)
                                    Spacer()
                                    Text(value.wifiDetails.ssid ?? interface.displayName)
                                }
                            }
                            HStack {
                                Text("IP").font(.system(size: 12, weight: .regular)).foregroundColor(.secondary)
                                Spacer()
                                if let raddr = value.raddr.v6 {
                                    Text(raddr)
                                        .font(.system(size: 8))
                                        .multilineTextAlignment(.trailing)
                                        .frame(maxWidth: .infinity, alignment: .center)
                                } else if let raddr = value.raddr.v4 {
                                    Text(raddr)
                                } else {
                                    Text("Unknown")
                                }
                            }
                        }
                    }
                } else if !Provider().systemWidgetsUpdatesState {
                    Text("Enable in Settings")
                        .font(.system(size: 12, weight: .regular))
                        .foregroundColor(.secondary)
                } else {
                    Text("No data")
                }
            }
            .containerBackground(for: .widget) {
                Color.clear
            }
        }
        .configurationDisplayName("Network widget")
        .description("Displays network stats")
        .supportedFamilies([.systemSmall])
